import React, { useState, useEffect } from 'react';

const MetricsPanel = () => {
  const [metrics, setMetrics] = useState({
    today: {
      totalRequests: 0,
      approved: 0,
      denied: 0,
      avgProcessingTime: '0 min',
      costSavings: '$0'
    },
    thisWeek: {
      totalRequests: 0,
      approvalRate: 0,
      automationRate: 0,
      costSavings: '$0'
    }
  });

  useEffect(() => {
    fetchMetrics();
  }, []);

  const fetchMetrics = async () => {
    try {
      const response = await fetch('/api/metrics');
      const data = await response.json();
      setMetrics(data);
    } catch (error) {
      // Use demo data if backend not available
      setMetrics({
        today: {
          totalRequests: 47,
          approved: 45,
          denied: 2,
          avgProcessingTime: '14.5 minutes',
          costSavings: '$564'
        },
        thisWeek: {
          totalRequests: 312,
          approvalRate: 95.8,
          automationRate: 95.2,
          costSavings: '$3,744'
        }
      });
    }
  };

  return (
    <div className="metrics-panel space-y-4">
      {/* Today's Metrics */}
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
          <i className="fas fa-chart-line text-blue-600"></i>
          Today's Metrics
        </h3>

        <div className="space-y-3">
          <div className="flex justify-between items-center">
            <span className="text-sm text-gray-600">Total Requests</span>
            <span className="text-lg font-bold text-blue-600">
              {metrics.today.totalRequests}
            </span>
          </div>

          <div className="flex justify-between items-center">
            <span className="text-sm text-gray-600">Approved</span>
            <span className="text-lg font-bold text-green-600">
              {metrics.today.approved}
            </span>
          </div>

          <div className="flex justify-between items-center">
            <span className="text-sm text-gray-600">Denied</span>
            <span className="text-lg font-bold text-red-600">
              {metrics.today.denied}
            </span>
          </div>

          <div className="border-t pt-3 mt-3">
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-600">Avg Processing Time</span>
              <span className="text-sm font-bold text-gray-800">
                {metrics.today.avgProcessingTime}
              </span>
            </div>
          </div>

          <div className="flex justify-between items-center">
            <span className="text-sm text-gray-600">Cost Savings</span>
            <span className="text-lg font-bold text-green-600">
              {metrics.today.costSavings}
            </span>
          </div>
        </div>
      </div>

      {/* This Week's Performance */}
      <div className="bg-gradient-to-br from-blue-500 to-indigo-600 rounded-lg shadow-lg p-6 text-white">
        <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
          <i className="fas fa-trophy"></i>
          This Week's Performance
        </h3>

        <div className="space-y-4">
          <div>
            <div className="flex justify-between items-center mb-2">
              <span className="text-sm opacity-90">Approval Rate</span>
              <span className="text-xl font-bold">{metrics.thisWeek.approvalRate}%</span>
            </div>
            <div className="w-full bg-white/20 rounded-full h-2">
              <div 
                className="bg-white rounded-full h-2 transition-all duration-500"
                style={{ width: `${metrics.thisWeek.approvalRate}%` }}
              ></div>
            </div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-2">
              <span className="text-sm opacity-90">Automation Rate</span>
              <span className="text-xl font-bold">{metrics.thisWeek.automationRate}%</span>
            </div>
            <div className="w-full bg-white/20 rounded-full h-2">
              <div 
                className="bg-white rounded-full h-2 transition-all duration-500"
                style={{ width: `${metrics.thisWeek.automationRate}%` }}
              ></div>
            </div>
          </div>

          <div className="border-t border-white/30 pt-4 mt-4">
            <div className="text-sm opacity-90">Total Cost Savings</div>
            <div className="text-3xl font-bold mt-1">{metrics.thisWeek.costSavings}</div>
          </div>

          <div className="bg-white/20 rounded-lg p-3 mt-4">
            <div className="text-xs opacity-80">Total Requests This Week</div>
            <div className="text-2xl font-bold">{metrics.thisWeek.totalRequests}</div>
          </div>
        </div>
      </div>

      {/* Key Stats */}
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h3 className="text-lg font-bold text-gray-800 mb-4">Key Statistics</h3>
        
        <div className="grid grid-cols-2 gap-4">
          <div className="text-center p-3 bg-blue-50 rounded-lg">
            <div className="text-2xl font-bold text-blue-600">95%</div>
            <div className="text-xs text-gray-600 mt-1">Automation</div>
          </div>

          <div className="text-center p-3 bg-green-50 rounded-lg">
            <div className="text-2xl font-bold text-green-600">96%</div>
            <div className="text-xs text-gray-600 mt-1">Time Saved</div>
          </div>

          <div className="text-center p-3 bg-purple-50 rounded-lg">
            <div className="text-2xl font-bold text-purple-600">$0.50</div>
            <div className="text-xs text-gray-600 mt-1">Cost/PA</div>
          </div>

          <div className="text-center p-3 bg-orange-50 rounded-lg">
            <div className="text-2xl font-bold text-orange-600">136%</div>
            <div className="text-xs text-gray-600 mt-1">ROI Y1</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default MetricsPanel;
